-- Garante a chave unica idempotente (no-op se ja existir)
DO $$ BEGIN
  ALTER TABLE public.bairro_airbnb_sp
    ADD CONSTRAINT bairro_airbnb_sp_bairro_periodo_key
    UNIQUE (bairro, cidade, periodo_inicio, periodo_fim);
EXCEPTION WHEN duplicate_table OR duplicate_object THEN NULL; END $$;

ON CONFLICT (bairro, cidade, periodo_inicio, periodo_fim) DO UPDATE SET
  n_listings_total = EXCLUDED.n_listings_total, n_listings_studio_1q = EXCLUDED.n_listings_studio_1q, pct_studio_1q = EXCLUDED.pct_studio_1q, adr_medio_studio = EXCLUDED.adr_medio_studio, ocupacao_media_studio = EXCLUDED.ocupacao_media_studio, receita_anual_media_studio = EXCLUDED.receita_anual_media_studio, estadia_media_noites = EXCLUDED.estadia_media_noites, porcentagem_reservas_30d_plus = EXCLUDED.porcentagem_reservas_30d_plus, rating_medio = EXCLUDED.rating_medio, percentual_superhost = EXCLUDED.percentual_superhost, media_reviews_por_listing = EXCLUDED.media_reviews_por_listing, pct_politica_flexivel = EXCLUDED.pct_politica_flexivel, pct_politica_moderada = EXCLUDED.pct_politica_moderada, pct_politica_rigida = EXCLUDED.pct_politica_rigida, preco_m2_residencial_medio = EXCLUDED.preco_m2_residencial_medio, aluguel_mensal_long_term_medio = EXCLUDED.aluguel_mensal_long_term_medio, dias_medio_venda_imovel = EXCLUDED.dias_medio_venda_imovel, numero_transacoes_imobiliarias_ano = EXCLUDED.numero_transacoes_imobiliarias_ano, indice_criminalidade = EXCLUDED.indice_criminalidade, grau_saturacao_index = EXCLUDED.grau_saturacao_index, risco_regulatorio = EXCLUDED.risco_regulatorio, risco_condominio = EXCLUDED.risco_condominio, area_media_estudio = EXCLUDED.area_media_estudio, yield_bruto_airbnb = EXCLUDED.yield_bruto_airbnb, yield_bruto_long_term = EXCLUDED.yield_bruto_long_term, delta_yield = EXCLUDED.delta_yield, score_rentabilidade = EXCLUDED.score_rentabilidade, score_liquidez = EXCLUDED.score_liquidez, score_crescimento_potencial = EXCLUDED.score_crescimento_potencial, nivel_confianca_dados = EXCLUDED.nivel_confianca_dados, fonte_primaria = EXCLUDED.fonte_primaria, data_atualizacao = EXCLUDED.data_atualizacao;
